+        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
+        _metrics = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;
+
+        // Train the final model on all available data
+        _model = pipeline.Fit(dataView);
+        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
+
+        // Extract the label ordering from the trained model's key-to-value mapping
+        var schema = _model.GetOutputSchema(dataView.Schema);
+        var labelColumn = schema.GetColumnOrNull("Label");
+        if (labelColumn.HasValue)
+        {
+            var keyValues = new VBuffer<ReadOnlyMemory<char>>();
+            labelColumn.Value.GetKeyValues(ref keyValues);
+            _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
+        }
+        else
+        {
+            _categoryLabels = ["Billing", "General", "Technical"];
+        }
+    }
+
+    public (string Category, Dictionary<string, float> Confidence) Predict(TicketRequest request)
+    {
+        var data = new TicketData
+        {
+            Subject = request.Subject,
+            Description = request.Description,
+            Priority = request.Priority
+        };
+
+        var prediction = _predictionEngine.Predict(data);
+
+        var confidence = new Dictionary<string, float>();
+        for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
+        {
+            confidence[_categoryLabels[i]] = prediction.Score[i];
+        }
+
+        return (prediction.Category, confidence);
+    }
+
+    public object GetMetrics() => new
+    {
+        MacroAccuracy = _metrics.MacroAccuracy,
+        MicroAccuracy = _metrics.MicroAccuracy,
+        LogLoss = _metrics.LogLoss,
+        LogLossReduction = _metrics.LogLossReduction
+    };
+}
